mapper.select:
SELECT ac1.id, ac1.article_id, ac1.user_id, ac1.collect_time, ac1.folder_id, ac1.status as collection_status, a.title, a.summary, a.cover_image, a.category_id, a.article_status, a.publish_time, a.original as original_status, a.read_count, a.like_count, a.comment_count, u.avatar, u.nickname, c.name as category_name, cf1.name as folder_name FROM article_collection ac1 JOIN article a ON ac1.article_id = a.id JOIN user u ON a.user_id = u.id LEFT JOIN category c ON a.category_id = c.id LEFT JOIN collection_folder cf1 ON ac1.folder_id = cf1.id WHERE ac1.user_id = #{userId}
AND ac1.folder_id = #{folderId}
AND a.title LIKE CONCAT('%', #{keyword}, '%')
AND a.deleted = 0 ORDER BY
ac1.collect_time DESC
a.like_count DESC
a.read_count DESC
ac1.collect_time DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM article_collection ac JOIN article a ON ac.article_id = a.id WHERE ac.user_id = #{userId}
AND ac.folder_id = #{folderId}
AND a.title LIKE CONCAT('%', #{keyword}, '%')
AND a.deleted = 0

